package com.example.springboot_oauth2_client.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class WebSecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(authorize -> authorize
                .requestMatchers("/initiate-oauth2-flow").permitAll()
                .anyRequest().authenticated()
            )
            .csrf(csrf -> csrf.disable()); // Temporarily disable CSRF as per user's "skip state parameter" request

        return http.build();
    }
}
package com.example.springboot_oauth2_client.controller;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.servlet.view.RedirectView;
import org.springframework.web.util.UriComponentsBuilder;

@Controller
public class OAuth2ClientInitiatorController {

    @Value("${app.oauth.client-id}")
    private String clientId;

    @Value("${app.oauth.redirect-uri}")
    private String redirectUri;

    @Value("${app.oauth.scope}")
    private String scope;

    @Value("${app.oauth.authorization-uri}")
    private String authorizationUri;

    @GetMapping("/initiate-oauth2-flow")
    public RedirectView redirectToAuthorizationServer() {
        String responseType = "code";

        UriComponentsBuilder uriBuilder = UriComponentsBuilder.fromUriString(authorizationUri)
                .queryParam("client_id", clientId)
                .queryParam("redirect_uri", redirectUri)
                .queryParam("scope", scope)
                .queryParam("response_type", responseType);

        String fullAuthorizationUrl = uriBuilder.build().toUriString();

        return new RedirectView(fullAuthorizationUrl);
    }
}
